import scala.xml._
import org.json4s._
import org.json4s.jackson.JsonMethods._

trait ConfigService {
  def parseConfig(xmlString: String): Map[String, Any]
}

class XMLConfigService extends ConfigService {
  override def parseConfig(xmlString: String): Map[String, Any] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "*").foldLeft(Map.empty[String, Any]) { case (acc, node) =>
      acc + ((node.label -> (node.text.trim match {
        case "true" => true
        case "false" => false
        case str if str.matches("-?\\d+(\\.\\d+)?") => str.toDouble
        case _ => node.text.trim
      })))
    }
  }
}

object ConfigServiceApp extends App {
  val configService = new XMLConfigService()
  val xmlString =
    """
      |<config>
      |  <setting1>true</setting1>
      |  <setting2>false</setting2>
      |  <setting3>42</setting3>
      |  <setting4>3.14</setting4>
      |  <setting5>example</setting5>
      |</config>
    """.stripMargin

  val configMap = configService.parseConfig(xmlString)
  println(configMap)
}